// Solution
function isValidRefName(name) {
	let forbiddenChars = '\/,<>|*?{}[]`';
	if (name.length > 200) return false;
	if (name.slice(0, -1) === '/' || name.slice(1) === '/') return false;
	for (let i = 0; i < name.length; i++) {
		if (forbiddenChars.indexOf(name[i]) !== -1) return false;
	}
	return true;
}

