class Solution:
    def is_valid_ref_name(self, name: str) -> bool:
        forbidden_chars = '\/,<>|*?{}[]`'
        if len(name) > 200:
            return False
        if name[0] == '\' or name[-1] == '\':
            return False
        for char in name:
            if char in forbidden_chars:
                return False
        return True
